    /// CC recipients
    cc_emails: []const []const u8,
    /// BCC recipients
    bcc_emails: []const []const u8,
    /// Message-ID header value
    message_id: ?[]const u8,
    /// List of attachment filenames
    attachments: []const []const u8,
};

/// Archive (ZIP/TAR/7Z) metadata.
