pub const OcrMetadata = struct {
    /// OCR language code(s) used
    language: []const u8,
    /// Tesseract Page Segmentation Mode (PSM)
    psm: i32,
    /// Output format (e.g., "text", "hocr")
    output_format: []const u8,
    /// Number of tables detected
    table_count: u32,
    table_rows: ?u32,
    table_cols: ?u32,
